tasks.description:
Create src/ports/mod.rs with trait interfaces. This file must import ONLY from the domain layer.

Use these exact imports at the top:
use crate::domain::{Weather, Forecast};

Traits:
- pub trait WeatherService { fn current(&self, city: &str) -> Result<Weather, String>; fn forecast(&self, city: &str, days: usize) -> Result<Forecast, String>; }
- pub struct CliRequest { pub city: String, pub show_forecast: bool, pub fahrenheit: bool }
- pub trait CliParser { fn parse(&self) -> Result<CliRequest, String>; }

Architecture rule: This file MUST NOT import from adapters or any external crate. Only crate::domain.

Return ONLY the complete Rust source file.

Create src/main.rs — the composition root. This is the ONLY file that may import from adapters.

Structure:
mod domain;
mod ports;
mod adapters;

use ports::{WeatherService, CliParser};
use adapters::{MockWeatherService, EnvCliParser};

fn main() {
    let cli = EnvCliParser;
    let weather = MockWeatherService;
    let request = match cli.parse() {
        Ok(r) => r,
        Err(e) => { eprintln!("Error: {}", e); std::process::exit(1); }
    };
    if request.show_forecast {
        match weather.forecast(&request.city, 5) {
            Ok(f) => {
                if request.fahrenheit { /* convert temps */ }
                println!("{}", f);
            }
            Err(e) => { eprintln!("Error: {}", e); std::process::exit(1); }
        }
    } else {
        match weather.current(&request.city) {
            Ok(w) => {
                if request.fahrenheit {
                    println!("Weather in {}: {:.1}°F", w.city, w.temp.to_fahrenheit());
                } else {
                    println!("{}", w);
                }
            }
            Err(e) => { eprintln!("Error: {}", e); std::process::exit(1); }
        }
    }
}

